// Option 1: env var (recommended)
process.env.DROPTHIS_API_KEY = "sk_...";
const dropthis = new Dropthis();

// Option 2: explicit
const dropthis = new Dropthis({ apiKey: "sk_..." });

// Option 3: string shorthand
const dropthis = new Dropthis("sk_...");

const { data, error } = await dropthis.publish("<h1>Secret</h1>", {
  password: "s3cret",
});

const { data, error } = await dropthis.publish("<h1>Hello</h1>");
if (error) {
  console.error(error.code, error.message);
  console.error("Status:", error.statusCode);
  return;
}
console.log(data.url);

// In CI, set DROPTHIS_API_KEY as a secret env var
const dropthis = new Dropthis();
const { data, error } = await dropthis.publish("./dist");
if (error) process.exit(1);
console.log(data.url);

await dropthis.update("drop_abc123", { title: "New title" });
// Or equivalently:
await dropthis.drops.update("drop_abc123", { title: "New title" });

const { data, error } = await dropthis.deployments.list("drop_abc123");
if (!error) {
  for (const dep of data.deployments) {
    console.log(dep.id, dep.status, dep.createdAt);
  }
}

const { data, error } = await dropthis.publish({
  kind: "files",
  files: [
    { path: "index.html", content: "<!doctype html>..." },
    { path: "style.css", content: "body{}" },
    { path: "app.js", content: "console.log(1)" },
  ],
  entry: "index.html",
});
if (!error) console.log(data.url);

const { data, error } = await dropthis.publish("https://example.com/report.html");
// or: await dropthis.publish({ kind: "source_url", sourceUrl: "https://example.com/report.html" });
if (!error) console.log(data.url);

const { data } = await dropthis.drops.get("drop_abc123");
const { error } = await dropthis.drops.update(
  "drop_abc123",
  { title: "Updated", ifRevision: data.revision },
);
if (error?.code === "http_409") {
  console.log("Conflict! Server revision:", error.currentRevision);
}
